package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.Payment;
import com.opengamma.strata.pricer.DiscountingPaymentPricer;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCds;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for CDS tranche trades based on ISDA standard model.
 * <p>
 * The CDS tranche represents a synthetic CDO tranche where loss protection is
 * limited to losses between the attachment and detachment points.
 * <p>
 * The present value is computed by scaling the underlying index CDS present value
 * by the tranche thickness (detachmentPoint - attachmentPoint), representing the
 * fraction of the index that this tranche covers.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The underlying CDS product pricer.
   */
  private final IsdaCdsProductPricer underlyingPricer;
  /**
   * The upfront fee pricer.
   */
  private final DiscountingPaymentPricer upfrontPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.underlyingPricer = new IsdaCdsProductPricer(formula);
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche trade.
   * <p>
   * The present value is calculated by pricing the underlying index CDS and
   * applying the tranche-specific loss allocation factor based on the
   * attachment and detachment points.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    CurrencyAmount productPv = presentValue(tranche, ratesProvider, settlementDate, priceType, refData);
    if (!trade.getUpfrontFee().isPresent()) {
      return productPv;
    }
    Payment upfrontFee = trade.getUpfrontFee().get();
    CurrencyAmount upfrontPv = upfrontPricer.presentValue(upfrontFee, ratesProvider.discountFactors(upfrontFee.getCurrency()));
    return productPv.plus(upfrontPv);
  }

  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value of the tranche is computed as the present value of the
   * underlying CDS (treated as a single-name CDS with the index credit curve)
   * scaled by the tranche thickness factor.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (!tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) {
      return CurrencyAmount.of(tranche.getCurrency(), 0d);
    }

    ResolvedCds cds = tranche.toSingleNameCds();
    LocalDate stepinDate = cds.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
    LocalDate effectiveStartDate = cds.calculateEffectiveStartDate(stepinDate);
    double recoveryRate = underlyingPricer.recoveryRate(cds, ratesProvider);

    LegalEntitySurvivalProbabilities survivalProbabilities =
        ratesProvider.survivalProbabilities(cds.getLegalEntityId(), cds.getCurrency());
    CreditDiscountFactors discountFactors = ratesProvider.discountFactors(cds.getCurrency());

    // Compute protection leg and risky annuity from the underlying pricer
    double protectionFull = underlyingPricer.protectionFull(cds, discountFactors, survivalProbabilities, referenceDate, effectiveStartDate);
    double protectionLeg = (1d - recoveryRate) * protectionFull;
    double rpv01 = underlyingPricer.riskyAnnuity(cds, discountFactors, survivalProbabilities, referenceDate, stepinDate, effectiveStartDate, priceType);

    // Tranche thickness: the fraction of the index covered
    double trancheThickness = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();

    // Index factor from the credit curve (if available, or default to 1.0)
    double indexFactor = getIndexFactor(cds, ratesProvider);

    // Scale the CDS PV by tranche thickness and index factor
    double signedNotional = cds.getBuySell().normalize(cds.getNotional());
    double amount = signedNotional * indexFactor * trancheThickness *
        (protectionLeg - rpv01 * cds.getFixedRate());

    return CurrencyAmount.of(cds.getCurrency(), amount);
  }

  /**
   * Calculates the present value on settlement date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value on settlement date
   */
  public CurrencyAmount presentValueOnSettle(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    return presentValue(tranche, ratesProvider, settlementDate, priceType, refData);
  }

  //-------------------------------------------------------------------------
  // calculate the settlement date
  private LocalDate calculateSettlementDate(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return trade.getProduct().calculateSettlementDateFromValuation(ratesProvider.getValuationDate(), refData);
  }

  // get the index factor from the credit rates provider (notional scaling factor)
  private double getIndexFactor(ResolvedCds cds, CreditRatesProvider ratesProvider) {
    try {
      LegalEntitySurvivalProbabilities survProbs =
          ratesProvider.survivalProbabilities(cds.getLegalEntityId(), cds.getCurrency());
      // Try to get index factor from curve info
      return survProbs.getSurvivalProbabilities()
          .findData(com.opengamma.strata.market.curve.CurveInfoType.CDS_INDEX_FACTOR)
          .orElse(1d);
    } catch (Exception e) {
      return 1d;
    }
  }

}

