102:   public PointSensitivityBuilder priceSensitivity(
103:       ResolvedCdsIndex cdsIndex,
104:       CreditRatesProvider ratesProvider,
105:       LocalDate referenceDate,
106:       ReferenceData refData) {
107: 
108:     ResolvedCds cds = cdsIndex.toSingleNameCds();
109:     return underlyingPricer.priceSensitivity(cds, ratesProvider, referenceDate, refData);
110:   }
111: 
112:   //-------------------------------------------------------------------------
113:   /**
114:    * Calculates the present value of the CDS index product.
115:    * <p>
116:    * The present value of the product is based on {@code referenceDate}.
117:    * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}. 
118:    * <p>
119:    * This method can calculate the clean or dirty present value, see {@link PriceType}. 
120:    * If calculating the clean value, the accrued interest is calculated based on the step-in date.
121:    * 
122:    * @param cdsIndex  the product
123:    * @param ratesProvider  the rates provider
124:    * @param referenceDate  the reference date
125:    * @param priceType  the price type
126:    * @param refData  the reference data
127:    * @return the present value
128:    */
129:   public CurrencyAmount presentValue(
130:       ResolvedCdsIndex cdsIndex,
131:       CreditRatesProvider ratesProvider,
132:       LocalDate referenceDate,
133:       PriceType priceType,
134:       ReferenceData refData) {
135: 
136:     if (isExpired(cdsIndex, ratesProvider)) {
137:       return CurrencyAmount.of(cdsIndex.getCurrency(), 0d);
138:     }
139:     ResolvedCds cds = cdsIndex.toSingleNameCds();
140:     LocalDate stepinDate = cds.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
141:     LocalDate effectiveStartDate = cds.calculateEffectiveStartDate(stepinDate);
142:     double recoveryRate = underlyingPricer.recoveryRate(cds, ratesProvider);
143:     Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> rates = reduceDiscountFactors(cds, ratesProvider);
144:     double protectionLeg = (1d - recoveryRate) *
145:         underlyingPricer.protectionFull(cds, rates.getFirst(), rates.getSecond(), referenceDate, effectiveStartDate);
146:     double rpv01 = underlyingPricer.riskyAnnuity(
147:         cds, rates.getFirst(), rates.getSecond(), referenceDate, stepinDate, effectiveStartDate, priceType);
148:     double amount =
149:         cds.getBuySell().normalize(cds.getNotional()) * rates.getThird() * (protectionLeg - rpv01 * cds.getFixedRate());
150:     return CurrencyAmount.of(cds.getCurrency(), amount);
