package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.Payment;
import com.opengamma.strata.pricer.DiscountingPaymentPricer;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCds;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for CDS tranche trades based on ISDA standard model.
 * <p>
 * A CDS tranche represents a slice of credit risk from a CDS index portfolio,
 * defined by attachment and detachment points.
 * <p>
 * The present value is computed by treating the tranche as an equivalent single-name
 * CDS with notional scaled by the tranche thickness (detachmentPoint - attachmentPoint),
 * using the index credit curve. This follows the homogeneous pool assumption.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The underlying CDS product pricer.
   */
  private final IsdaCdsProductPricer underlyingPricer;
  /**
   * The upfront fee pricer.
   */
  private final DiscountingPaymentPricer upfrontPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.underlyingPricer = new IsdaCdsProductPricer(formula);
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche trade.
   * <p>
   * The present value is calculated from the settlement date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = tranche.calculateSettlementDateFromValuation(ratesProvider.getValuationDate(), refData);
    CurrencyAmount productPv = presentValue(tranche, ratesProvider, settlementDate, priceType, refData);
    if (!trade.getUpfrontFee().isPresent()) {
      return productPv;
    }
    Payment upfrontFee = trade.getUpfrontFee().get();
    CurrencyAmount upfrontPv = upfrontPricer.presentValue(upfrontFee, ratesProvider.discountFactors(upfrontFee.getCurrency()));
    return productPv.plus(upfrontPv);
  }

  /**
   * Calculates the present value on the settlement date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value on the settlement date
   */
  public CurrencyAmount presentValueOnSettle(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = tranche.calculateSettlementDateFromValuation(ratesProvider.getValuationDate(), refData);
    return presentValue(tranche, ratesProvider, settlementDate, priceType, refData);
  }

  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The tranche PV is computed by scaling the underlying CDS index PV by the
   * tranche thickness factor (detachmentPoint - attachmentPoint). Under the
   * homogeneous pool assumption, this approximates the expected loss within
   * the tranche boundaries.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date (typically settlement date)
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (!tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) {
      return CurrencyAmount.of(tranche.getCurrency(), 0d);
    }

    // Tranche thickness: the fraction of the index covered by this tranche
    double trancheThickness = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();

    // Price the underlying CDS using the index credit curve
    ResolvedCds cds = tranche.toSingleNameCds();
    double price = underlyingPricer.price(cds, ratesProvider, referenceDate, priceType, refData);

    // Scale PV by tranche thickness: only this fraction of the portfolio is affected
    double signedNotional = cds.getBuySell().normalize(cds.getNotional());
    double amount = signedNotional * trancheThickness * price;

    return CurrencyAmount.of(cds.getCurrency(), amount);
  }

}
